type siteWhere[Q psql.Filterable] struct {
	AddressID         psql.WhereMod[Q, int32]
	Created           psql.WhereMod[Q, time.Time]
	CreatorID         psql.WhereMod[Q, int32]
	FileID            psql.WhereNullMod[Q, int32]
	ID                psql.WhereMod[Q, int32]
	Notes             psql.WhereMod[Q, string]
	OrganizationID    psql.WhereMod[Q, int32]
	OwnerName         psql.WhereMod[Q, string]
	OwnerPhoneE164    psql.WhereNullMod[Q, string]
	ResidentOwned     psql.WhereNullMod[Q, bool]
	ResidentPhoneE164 psql.WhereNullMod[Q, string]
	Tags              psql.WhereMod[Q, pgtypes.HStore]
	Version           psql.WhereMod[Q, int32]
}

func (siteWhere[Q]) AliasedAs(alias string) siteWhere[Q] {
	return buildSiteWhere[Q](buildSiteColumns(alias))
}

func buildSiteWhere[Q psql.Filterable](cols siteColumns) siteWhere[Q] {
	return siteWhere[Q]{
		AddressID:         psql.Where[Q, int32](cols.AddressID),
		Created:           psql.Where[Q, time.Time](cols.Created),
		CreatorID:         psql.Where[Q, int32](cols.CreatorID),
		FileID:            psql.WhereNull[Q, int32](cols.FileID),
		ID:                psql.Where[Q, int32](cols.ID),
		Notes:             psql.Where[Q, string](cols.Notes),
		OrganizationID:    psql.Where[Q, int32](cols.OrganizationID),
		OwnerName:         psql.Where[Q, string](cols.OwnerName),
		OwnerPhoneE164:    psql.WhereNull[Q, string](cols.OwnerPhoneE164),
		ResidentOwned:     psql.WhereNull[Q, bool](cols.ResidentOwned),
		ResidentPhoneE164: psql.WhereNull[Q, string](cols.ResidentPhoneE164),
		Tags:              psql.Where[Q, pgtypes.HStore](cols.Tags),
		Version:           psql.Where[Q, int32](cols.Version),
	}
}

func (o *Site) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Address":
		rel, ok := retrieved.(*Address)
		if !ok {
			return fmt.Errorf("site cannot load %T as %q", retrieved, name)
		}

		o.R.Address = rel

		if rel != nil {
			rel.R.Site = o
		}
		return nil
	case "CreatorUser":
		rel, ok := retrieved.(*User)
		if !ok {
			return fmt.Errorf("site cannot load %T as %q", retrieved, name)
		}

		o.R.CreatorUser = rel

		if rel != nil {
			rel.R.CreatorSites = SiteSlice{o}
		}
		return nil
	case "File":
		rel, ok := retrieved.(*FileuploadFile)
		if !ok {
			return fmt.Errorf("site cannot load %T as %q", retrieved, name)
		}

		o.R.File = rel

		if rel != nil {
			rel.R.Sites = SiteSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("site has no relationship %q", name)
	}
}

type sitePreloader struct {
	Address     func(...psql.PreloadOption) psql.Preloader
	CreatorUser func(...psql.PreloadOption) psql.Preloader
	File        func(...psql.PreloadOption) psql.Preloader
}

func buildSitePreloader() sitePreloader {
	return sitePreloader{
		Address: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Address, AddressSlice](psql.PreloadRel{
				Name: "Address",
				Sides: []psql.PreloadSide{
					{
						From:        Sites,
						To:          Addresses,
						FromColumns: []string{"address_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Addresses.Columns.Names(), opts...)
		},
		CreatorUser: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*User, UserSlice](psql.PreloadRel{
				Name: "CreatorUser",
				Sides: []psql.PreloadSide{
					{
						From:        Sites,
						To:          Users,
						FromColumns: []string{"creator_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Users.Columns.Names(), opts...)
		},
		File: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*FileuploadFile, FileuploadFileSlice](psql.PreloadRel{
				Name: "File",
				Sides: []psql.PreloadSide{
					{
						From:        Sites,
						To:          FileuploadFiles,
						FromColumns: []string{"file_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, FileuploadFiles.Columns.Names(), opts...)
		},
	}
}

type siteThenLoader[Q orm.Loadable] struct {
	Address     func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	CreatorUser func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	File        func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildSiteThenLoader[Q orm.Loadable]() siteThenLoader[Q] {
	type AddressLoadInterface interface {
		LoadAddress(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type CreatorUserLoadInterface interface {
		LoadCreatorUser(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type FileLoadInterface interface {
		LoadFile(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return siteThenLoader[Q]{
		Address: thenLoadBuilder[Q](
			"Address",
			func(ctx context.Context, exec bob.Executor, retrieved AddressLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadAddress(ctx, exec, mods...)
			},
		),
		CreatorUser: thenLoadBuilder[Q](
			"CreatorUser",
			func(ctx context.Context, exec bob.Executor, retrieved CreatorUserLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCreatorUser(ctx, exec, mods...)
			},
		),
		File: thenLoadBuilder[Q](
			"File",
			func(ctx context.Context, exec bob.Executor, retrieved FileLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadFile(ctx, exec, mods...)
			},
		),
	}
}

// LoadAddress loads the site's Address into the .R struct
func (o *Site) LoadAddress(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Address = nil

	related, err := o.Address(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.Site = o

	o.R.Address = related
	return nil
}

// LoadAddress loads the site's Address into the .R struct
func (os SiteSlice) LoadAddress(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	addresses, err := os.Address(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range addresses {

			if !(o.AddressID == rel.ID) {
				continue
			}

			rel.R.Site = o

			o.R.Address = rel
			break
		}
	}

	return nil
}

// LoadCreatorUser loads the site's CreatorUser into the .R struct
func (o *Site) LoadCreatorUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.CreatorUser = nil

	related, err := o.CreatorUser(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.CreatorSites = SiteSlice{o}

	o.R.CreatorUser = related
	return nil
}

// LoadCreatorUser loads the site's CreatorUser into the .R struct
func (os SiteSlice) LoadCreatorUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	users, err := os.CreatorUser(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range users {

			if !(o.CreatorID == rel.ID) {
				continue
			}

			rel.R.CreatorSites = append(rel.R.CreatorSites, o)

			o.R.CreatorUser = rel
			break
		}
	}

	return nil
}

// LoadFile loads the site's File into the .R struct
func (o *Site) LoadFile(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.File = nil

	related, err := o.File(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.Sites = SiteSlice{o}

	o.R.File = related
	return nil
}

// LoadFile loads the site's File into the .R struct
func (os SiteSlice) LoadFile(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	fileuploadFiles, err := os.File(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range fileuploadFiles {
			if !o.FileID.IsValue() {
				continue
			}

			if !(o.FileID.IsValue() && o.FileID.MustGet() == rel.ID) {
				continue
			}

			rel.R.Sites = append(rel.R.Sites, o)

			o.R.File = rel
			break
		}
	}

	return nil
}

type siteJoins[Q dialect.Joinable] struct {
	typ         string
	Address     modAs[Q, addressColumns]
	CreatorUser modAs[Q, userColumns]
	File        modAs[Q, fileuploadFileColumns]
}

func (j siteJoins[Q]) aliasedAs(alias string) siteJoins[Q] {
	return buildSiteJoins[Q](buildSiteColumns(alias), j.typ)
}

func buildSiteJoins[Q dialect.Joinable](cols siteColumns, typ string) siteJoins[Q] {
	return siteJoins[Q]{
		typ: typ,
		Address: modAs[Q, addressColumns]{
			c: Addresses.Columns,
			f: func(to addressColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Addresses.Name().As(to.Alias())).On(
						to.ID.EQ(cols.AddressID),
					))
				}

				return mods
			},
		},
		CreatorUser: modAs[Q, userColumns]{
			c: Users.Columns,
			f: func(to userColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Users.Name().As(to.Alias())).On(
						to.ID.EQ(cols.CreatorID),
					))
				}

				return mods
			},
		},
		File: modAs[Q, fileuploadFileColumns]{
			c: FileuploadFiles.Columns,
			f: func(to fileuploadFileColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, FileuploadFiles.Name().As(to.Alias())).On(
						to.ID.EQ(cols.FileID),
					))
				}

				return mods
			},
		},
	}
}
